import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F11: 處分重大資產與資本配置","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F11_處分重大資產與資本配置.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F11_處分重大資產與資本配置.md"}'),l={name:"審計報告庫/財務審計/6442_光聖/20260504/F11_處分重大資產與資本配置.md"};function i(n,a,h,s,d,_){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="f11-處分重大資產與資本配置" tabindex="-1">F11: 處分重大資產與資本配置 <a class="header-anchor" href="#f11-處分重大資產與資本配置" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：近三年光聖無重大資產處分行為，2025 年處分固定資產損失僅 795 萬（佔營收 0.007%），屬設備汰換性質。無變賣祖產美化財報之虞，獲利純度極高。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：2025 年報</li></ul><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>年報揭露 2025 年處分不動產廠房設備損失 795 萬，2024 年損失 725 萬，均屬常態性設備汰換，佔營收比可忽略。業外收支中「其他利益及損失」合計 -1.93 億（含匯兌損失 1.65 億、金融資產評價損失 2,119 萬），但無任何一次性資產處分利益。光聖的獲利全部來自主業營運，無資本財美化利潤。</p><p><strong>評級：S（優）</strong> — 無重大資產處分，獲利純度 100%。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>獲利含金量穿透：</strong> 營益率 24.1% 與稅前純益率（扣非後）約 22.2% 僅差 1.9%，營益率即主導核心獲利。本業營業利益 25.39 億遠高於業外合計盈虧，業外匯兌波動屬短期影響，不改變本業紮實的獲利品質。</p><p><strong>戰略意圖判別：</strong> 資金配置集中於擴產——2024 年 CapEx 7.46 億（營收比 11.8%）、2025 年 CapEx 5.44 億（營收比 5.1%），全數為菲律賓及寧波廠建設。無處分核心資產行為，處分損失均為設備更新產生的正常報廢損失，非策略性變現。</p><p><strong>資產結構變動：</strong> PP&amp;E 淨額從 5.56 億（2023）增至 11.47 億（2025），累積增額 5.91 億可對應同期 CapEx 約 14.45 億，差額反映折舊攤銷（約 8.5 億）。全為產能擴張，無資產出售紀錄。</p><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li>無資產處分同時也無積極的資產活化策略，光聖 11.47 億固定資產中老舊設備可能成為生產效率瓶頸，若設備更新延遲將影響良率與交期穩定性。</li><li>CB 發行 23.5 億若資金未充分投入高回報專案，將形成資金閒置成本。雖利息僅 2,145 萬，但資金報酬率若低於資金成本，將拖累 ROE 與股東權益報酬表現。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li>零資產處分代表獲利 100% 來自本業營運，是最純淨的投資標的，財報可信度極高，無一次性美化利潤的疑慮。</li><li>CapEx 完全聚焦核心產能擴張（菲律賓廠、CPO 試產線），配置方向明確且與產業成長趨勢一致。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>獲利純度無可挑剔，但資產活化與 CB 資金運用效率將是 2026-2027 年 ROE 能否持續提升的關鍵。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>年報資料：6442 2025 Q4 合併財報第 50 頁（業外明細附註）</li><li>原始數據：FinMind TaiwanStockFinancialStatements</li><li>數據查詢日期：2026-05-04</li></ul>',23)])])}const u=e(l,[["render",i]]);export{p as __pageData,u as default};
